DailyCRWExpiration dce = new DailyCRWExpiration("error");
List reportees = new ArrayList();
int rDays  = 30;		
 //String manager = "10174665";
  String accountExpire = "accountExpires";
  
   
	 public List getManagers(){
		List outIdn = new ArrayList();
	  QueryOptions qo = new QueryOptions();
		 //Filter f = Filter.ignoreCase(Filter.and(Filter.eq("managerStatus", true),Filter.eq("inactive", false), Filter.eq("correlated",true), Filter.eq("name","10375696")));
     Filter f = Filter.ignoreCase(Filter.and(Filter.eq("managerStatus", true),Filter.eq("inactive", false), Filter.eq("correlated",true)));
		 qo.addFilter(f);
		 Iterator iterator = context.search(Identity.class, qo);
		 while (iterator.hasNext()) {
      Identity idn = (Identity) iterator.next();
			outIdn.add(idn);
		}
     return outIdn;
	 }
public boolean sendEmail(Map finalDataMap, String toAddress){
	String finalRecords = null;
	Map mailargs = new HashMap();
    String strTemplate = "Ascension-EmailTemplate-CWR-AccountExpirationEmail";
    String fileName = "account_expiration_data.csv";
    EmailTemplate template = context.getObjectByName(EmailTemplate.class, strTemplate);
    EmailOptions mailopts = null;
    EmailFileAttachment attachment = null;
	dataBuilder = new StringBuilder();
	dataBuilder.append("\"Index\",\"User Type\",\"User DisplayName\",\"User Name\",\"First Name\",\"Last Name\",\"User Email \",\"Manager Name\",\"Contractor Manager Name\",\"Contractor Manager Email\",\"Domain Name\",\"Account ID\",\"Expiration Date\"\n");
	  List records  = finalDataMap.get("dataList");
    int i = 0;
	  for (String rec: records) {
        dataBuilder.append(i.toString());
        dataBuilder.append(",");
        dataBuilder.append(rec);
        dataBuilder.append("\n");
        i++;
    }
    finalRecords = dataBuilder.toString().replaceAll("null", "");
		mailopts = new EmailOptions(toAddress, mailargs);
    attachment = new EmailFileAttachment(fileName, EmailFileAttachment.MimeType.MIME_CSV, finalRecords.getBytes("UTF-8"));
    mailopts.addAttachment(attachment);
    context.sendEmailNotification(template, mailopts);
  return true;
}
Map finalData;
List managerList = getManagers();
 
if(null != managerList @and !managerList.isEmpty()){
	for(Identity i : managerList){
		String managerEmail = i.getEmail() != null ? i.getEmail().toString() : null;
    String externalEmail = i.getAttribute("externalEmail") != null ? i.getAttribute("externalEmail").toString() : null;
		String toAddress = null;
		if(null != managerEmail){toAddress = managerEmail;}
		else if(null != externalEmail @and null != toAddress){ toAddress = toAddress+","+externalEmail;}
		else if(null != externalEmail @and null == toAddress){toAddress = externalEmail;}
		if(null != toAddress){
    String idnTypes = "contractor,non-hr contractor";
    List listOfReportees = dce.getFilteredADLinksForManager(i.getName(),rDays,idnTypes);
    if(null != listOfReportees @and !listOfReportees.isEmpty()){
         finalData = new HashMap();
				 finalData.put("dataList",listOfReportees);
         sendEmail(finalData,toAddress);
        
     }else{
       //DO NOTHING
     }
		}
	}	 
}
